input.command:
kubectl patch statefulset elasticsearch -n elasticsearch --type=strategic-merge -p '{
  "spec": {
    "template": {
      "spec": {
        "volumes": [
          {
            "name": "es-logs",
            "emptyDir": {}
          },
          {
            "name": "metricbeat-config",
            "configMap": {
              "name": "metricbeat-config"
            }
          },
          {
            "name": "filebeat-config",
            "configMap": {
              "name": "filebeat-config"
            }
          },
          {
            "name": "es-log4j2",
            "configMap": {
              "name": "es-log4j2-config"
            }
          }
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {
                "name": "es-logs",
                "mountPath": "/usr/share/elasticsearch/logs"
              },
              {
                "name": "es-log4j2",
                "mountPath": "/usr/share/elasticsearch/config/log4j2.properties",
                "subPath": "log4j2.properties"
              }
            ]
          },
          {
            "name": "metricbeat",
            "image": "docker.elastic.co/beats/metricbeat:7.17.9",
            "args": ["-e", "-c", "/usr/share/metricbeat/metricbeat.yml"],
            "env": [
              {
                "name": "ELASTIC_PASSWORD",
                "valueFrom": {
                  "secretKeyRef": {
                    "name": "elastic-password",
                    "key": "password"
                  }
                }
              }
            ],
            "resources": {
              "limits": {"cpu": "200m", "memory": "256Mi"},
              "requests": {"cpu": "50m", "memory": "128Mi"}
            },
            "volumeMounts": [
              {
                "name": "metricbeat-config",
                "mountPath": "/usr/share/metricbeat/metricbeat.yml",
                "subPath": "metricbeat.yml"
              },
              {
                "name": "certs",
                "mountPath": "/usr/share/elasticsearch/config/certs",
                "readOnly": true
              }
            ]
          },
          {
            "name": "filebeat",
            "image": "docker.elastic.co/beats/filebeat:7.17.9",
            "args": ["-e", "-c", "/usr/share/filebeat/filebeat.yml"],
            "resources": {
              "limits": {"cpu": "200m", "memory": "256Mi"},
              "requests": {"cpu": "50m", "memory": "128Mi"}
            },
            "volumeMounts": [
              {
                "name": "filebeat-config",
                "mountPath": "/usr/share/filebeat/filebeat.yml",
                "subPath": "filebeat.yml"
              },
              {
                "name": "es-logs",
                "mountPath": "/var/log/elasticsearch"
              }
            ]
          }
        ]
      }
    }
  }
}' 2>&1

